// src/api/authApi.ts
import apiClient from '../api/apiClient';
import {ApiResponse} from "../interface/ApiResponse";
import {LoginRequest, LoginResponse} from "../interface/LoginData";


export interface VerifyPasswordDto {
    password: string;
}


/**
 * 로그인
 */
export const login = (data: LoginRequest) =>
    apiClient.post<ApiResponse<LoginResponse>>(`/api/front/auth/login`, data);


/**
 * 토큰 응답 처리
 */
export const handleTokenResponse = (response: ApiResponse<LoginResponse>) => {
    const { accessToken, refreshToken, adminCode } = response.data;

    localStorage.setItem('accessToken', accessToken);
    localStorage.setItem('refreshToken', refreshToken);
    localStorage.setItem("adminCode", String(adminCode));

    return response.data;
};
